const CONFIG = {
  SPREADSHEET_ID: '1kwXtpKxtQE52lFnz5MRRV0dnzeftN_X5tD69CL12ycU',
  SHEET_IDS: {
    CONFIG: 1170756615,
    MATCHES: 996094587,
    WATCHLIST: 715101038,
    RECOMMENDATIONS: 532487099,
  },
  TIMEZONE: 'Asia/Seoul',
  AI_PROVIDER: 'gemini',
  AI_MODEL: 'gemini-2.0-flash',
  AI_TEMPERATURE: '0.3',
  AI_MAX_TOKENS: '4096',
  PROCESS_MODES: ['A', 'B', 'C'],
  SKIP_IF_HAS_CONDITION: true,
  SKIP_IF_HAS_RECOMMENDATION: false,
  MIN_PRIORITY: 1,
  MAX_PRIORITY: 5,
  PRE_MATCH_WINDOW_HOURS: 24,
  // NEW: Batch size for AI calls
  AI_BATCH_SIZE: 10,
};

return { json: CONFIG };

// Filter Eligible Matches for Condition Generation
const allMatches = $input.all();
if (!allMatches.length) {
  console.log('[Filter Eligible] No matches in watchlist');
  return [];
}

const config = $('Set Config').first().json || {};
const TIMEZONE = config.TIMEZONE || 'UTC';
const PRE_MATCH_WINDOW_HOURS = Number(config.PRE_MATCH_WINDOW_HOURS ?? 24);
const PROCESS_MODES = config.PROCESS_MODES || ['A', 'B', 'C'];
const SKIP_IF_HAS_CONDITION = config.SKIP_IF_HAS_CONDITION !== false;
const SKIP_IF_HAS_RECOMMENDATION = config.SKIP_IF_HAS_RECOMMENDATION === true;
const MIN_PRIORITY = Number(config.MIN_PRIORITY ?? 1);
const MAX_PRIORITY = Number(config.MAX_PRIORITY ?? 5);

const now = new Date();

function parseLocalDateTime(dateStr, timeStr) {
  if (!dateStr) return null;
  const dateParts = String(dateStr).trim().split('-');
  if (dateParts.length !== 3) return null;
  const year = Number(dateParts[0]);
  const month = Number(dateParts[1]);
  const day = Number(dateParts[2]);
  let hour = 0, minute = 0;
  if (timeStr) {
    const tParts = String(timeStr).trim().split(':');
    hour = Number(tParts[0] || 0);
    minute = Number(tParts[1] || 0);
  }
  if (!year || !month || !day) return null;
  return new Date(Date.UTC(year, month - 1, day, hour, minute, 0, 0));
}

const eligible = [];
const skipped = { hasCondition: 0, hasRecommendation: 0, wrongMode: 0, wrongPriority: 0, tooFarAway: 0, invalid: 0 };

for (const item of allMatches) {
  const row = item.json || {};
  const matchId = String(row.match_id || '').trim();

  if (!matchId) {
    skipped.invalid++;
    continue;
  }

  const mode = String(row.mode || 'B').trim().toUpperCase();
  if (!PROCESS_MODES.includes(mode)) {
    skipped.wrongMode++;
    continue;
  }

  const priority = Number(row.priority ?? 3);
  if (priority < MIN_PRIORITY || priority > MAX_PRIORITY) {
    skipped.wrongPriority++;
    continue;
  }

  const existingCondition = String(row.custom_conditions || '').trim();
  if (SKIP_IF_HAS_CONDITION && existingCondition && existingCondition !== '(none)') {
    skipped.hasCondition++;
    continue;
  }

  const existingRecommendation = String(row.recommended_custom_condition || '').trim();
  if (SKIP_IF_HAS_RECOMMENDATION && existingRecommendation) {
    skipped.hasRecommendation++;
    continue;
  }

  const dateStr = String(row.date || '').trim();
  const kickoffStr = String(row.kickoff || '').trim();
  const matchStart = parseLocalDateTime(dateStr, kickoffStr);

  if (matchStart) {
    const hoursUntilKickoff = (matchStart - now) / (1000 * 60 * 60);
    if (hoursUntilKickoff < -2 || hoursUntilKickoff > PRE_MATCH_WINDOW_HOURS) {
      skipped.tooFarAway++;
      continue;
    }
  }

  eligible.push({
    json: {
      ...row,
      match_id: matchId,
      mode,
      priority,
      hours_until_kickoff: matchStart ? Math.round((matchStart - now) / (1000 * 60 * 60) * 10) / 10 : null,
    }
  });
}

console.log(`[Filter Eligible] Total: ${allMatches.length}, Eligible: ${eligible.length}`);
console.log(`[Filter Eligible] Skipped - hasCondition: ${skipped.hasCondition}, hasRecommendation: ${skipped.hasRecommendation}, wrongMode: ${skipped.wrongMode}, wrongPriority: ${skipped.wrongPriority}, tooFarAway: ${skipped.tooFarAway}, invalid: ${skipped.invalid}`);

return eligible;

// Merge Prediction with Match Data (runs for each item)
// ENHANCED: Bao gồm dữ liệu teams chi tiết cho AI phân tích sâu
// Cấu trúc gọn gàng, loại bỏ URLs/logos không cần thiết

const matchData = $items('Filter Eligible Matches')[$itemIndex].json;
const apiResp = $json || {};

// Check for API errors
if (apiResp.errors) {
  const err = apiResp.errors.rateLimit || apiResp.errors.fixture || apiResp.errors.requests;
  if (err) {
    console.log(`[Merge] API Error for ${matchData.match_id}: ${err}`);
  }
}

// Extract prediction from response
let prediction = null;
if (Array.isArray(apiResp.response) && apiResp.response.length > 0) {
  prediction = apiResp.response[0];
}

// Helper: Extract compact team stats
function extractTeamStats(team, isHome) {
  if (!team) return null;

  const last5 = team.last_5 || {};
  const league = team.league || {};
  const fixtures = league.fixtures || {};
  const goals = league.goals || {};
  const goalsFor = goals.for || {};
  const goalsAgainst = goals.against || {};

  // Extract goals by minute (chỉ giữ percentage, bỏ total)
  function extractMinuteStats(minuteData) {
    if (!minuteData) return null;
    const result = {};
    for (const period of ['0-15', '16-30', '31-45', '46-60', '61-75', '76-90']) {
      const pct = minuteData[period]?.percentage;
      if (pct) result[period] = pct;
    }
    return Object.keys(result).length > 0 ? result : null;
  }

  return {
    name: team.name,

    // Phong độ 5 trận gần nhất
    last_5: {
      form: last5.form,           // "60%"
      attack: last5.att,          // "67%"
      defense: last5.def,         // "56%"
      avg_scored: last5.goals?.for?.average,    // "2.4"
      avg_conceded: last5.goals?.against?.average  // "1.6"
    },

    // Form cả mùa (chuỗi W/D/L)
    season_form: league.form,     // "WDLDDLDWDDLLLWWWWLWWL"

    // Thống kê thắng/hòa/thua - chỉ lấy phần relevant (home cho home team, away cho away team)
    record: {
      played: isHome ? fixtures.played?.home : fixtures.played?.away,
      wins: isHome ? fixtures.wins?.home : fixtures.wins?.away,
      draws: isHome ? fixtures.draws?.home : fixtures.draws?.away,
      loses: isHome ? fixtures.loses?.home : fixtures.loses?.away,
      // Thêm total để so sánh
      total: {
        played: fixtures.played?.total,
        wins: fixtures.wins?.total,
        draws: fixtures.draws?.total,
        loses: fixtures.loses?.total
      }
    },

    // Bàn thắng theo khung giờ - RẤT HỮU ÍCH cho điều kiện Minute-based
    goals_by_minute: {
      scored: extractMinuteStats(goalsFor.minute),
      conceded: extractMinuteStats(goalsAgainst.minute)
    },

    // Trung bình bàn thắng/thua
    avg_goals: {
      scored: isHome ? goalsFor.average?.home : goalsFor.average?.away,
      conceded: isHome ? goalsAgainst.average?.home : goalsAgainst.average?.away
    },

    // Thống kê đặc biệt
    clean_sheets: league.clean_sheet?.total,
    failed_to_score: league.failed_to_score?.total,

    // Chuỗi thắng/thua lớn nhất
    biggest_streak: {
      wins: league.biggest?.streak?.wins,
      draws: league.biggest?.streak?.draws,
      loses: league.biggest?.streak?.loses
    },

    // Under/Over stats - hữu ích cho Total goals conditions
    under_over: {
      scored: goalsFor.under_over,   // { "0.5": {over, under}, "1.5": {...}, ... }
      conceded: goalsAgainst.under_over
    }
  };
}

// Build ENHANCED structured prediction data
let preMatchPrediction = null;
let preMatchSummary = '';

if (prediction) {
  const pred = prediction.predictions || {};
  const comp = prediction.comparison || {};
  const teams = prediction.teams || {};

  preMatchPrediction = {
    // Core predictions (giữ nguyên)
    predictions: {
      winner: pred.winner ? { 
        id: pred.winner.id,
        name: pred.winner.name,
        comment: pred.winner.comment  // "Win or draw"
      } : null,
      win_or_draw: pred.win_or_draw ?? null,
      under_over: pred.under_over,    // "+2.5" hoặc "-2.5"
      goals: pred.goals ? {
        home: pred.goals.home,
        away: pred.goals.away
      } : null,
      percent: pred.percent ? {
        home: pred.percent.home,
        draw: pred.percent.draw,
        away: pred.percent.away
      } : null,
      advice: pred.advice
    },

    // Comparison scores
    comparison: {
      form: comp.form,           // { home: "47%", away: "53%" }
      att: comp.att,             // Attack comparison
      def: comp.def,             // Defense comparison  
      poisson: comp.poisson_distribution,  // Poisson distribution
      h2h: comp.h2h,             // Head to head
      goals: comp.goals,         // Goals comparison
      total: comp.total          // Overall rating { home: "60.2%", away: "39.8%" }
    },

    // ENHANCED: Team detailed stats
    teams: {
      home: extractTeamStats(teams.home, true),
      away: extractTeamStats(teams.away, false)
    }
  };

  // Build summary (giữ nguyên logic cũ)
  const parts = [];
  if (pred.advice) parts.push(pred.advice);
  if (pred.winner?.name) parts.push(`Favourite: ${pred.winner.name}`);
  if (pred.percent) {
    parts.push(`H${pred.percent.home || '?'} D${pred.percent.draw || '?'} A${pred.percent.away || '?'}`);
  }
  if (pred.goals?.home && pred.goals?.away) {
    parts.push(`Expected: ${pred.goals.home}-${pred.goals.away}`);
  }
  if (comp.total?.home && comp.total?.away) {
    parts.push(`Rating: ${comp.total.home} vs ${comp.total.away}`);
  }
  if (pred.under_over) {
    parts.push(`O/U: ${pred.under_over}`);
  }
  preMatchSummary = parts.join(' | ');
}

return {
  json: {
    ...matchData,
    pre_match_prediction: preMatchPrediction,
    pre_match_prediction_summary: preMatchSummary,
    has_prediction: !!prediction,
  }
};

// NEW: Batch matches for AI processing
