const config = $('Set Config').first().json || {};
const BATCH_SIZE = config.AI_BATCH_SIZE || 10;

if (!items.length) return [];

const batches = [];
for (let i = 0; i < items.length; i += BATCH_SIZE) {
  const batchMatches = items.slice(i, i + BATCH_SIZE).map(item => item.json);
  batches.push({
    json: {
      batch_index: Math.floor(i / BATCH_SIZE) + 1,
      batch_size: batchMatches.length,
      matches: batchMatches,
    }
  });
}

console.log(`[Batch Matches] Created ${batches.length} batches from ${items.length} matches (batch size: ${BATCH_SIZE})`);
return batches;

// Build AI Prompt - Enhanced for Deep Analysis
// ============================================================
// CHANGE: Added reason_vi (Vietnamese) to output format
// ============================================================

const batchData = $json || {};
const config = batchData.config || {};
const matches = Array.isArray(batchData.matches) ? batchData.matches : [];
const batchIndex = batchData.batch_index || 1;

if (!matches.length) {
  return { json: { ai_prompt: "", matches: [], batch_index: batchIndex } };
}

// --------------------
// Helper function để build ENHANCED context cho MỖI match
// --------------------
function buildMatchContext(data) {
  const match = data.match || {};
  const stats = data.stats || data.live_stats || {};
  const statsCompact = data.stats_compact || stats || {};
  const events = Array.isArray(data.events_compact) ? data.events_compact : [];

  const homeName = match.home || data.home_team || "Home";
  const awayName = match.away || data.away_team || "Away";
  const league = match.league || data.league || "Unknown league";
  const matchId = data.match_id || match.match_id || "N/A";

  const minuteRaw = match.minute ?? data.minute ?? data.match_minute ?? null;
  const minute = (minuteRaw === "" || minuteRaw === undefined) ? null : minuteRaw;

  const score = match.score || data.score || "0-0";
  const status = match.status || data.status || "UNKNOWN";

  const statsAvailable = !!data.stats_available;
  const oddsAvailable = !!data.odds_available;

  const oddsCanonical = data.odds_canonical || {};
  const preMatchPrediction = data.pre_match_prediction || null;
  const preMatchPredictionSummary = data.pre_match_prediction_summary || "";
  const customConditionsExisting = (data.custom_conditions || "").trim();

  // Extract ENHANCED pre-match data including team stats
  let preMatchEnhanced = null;
  if (preMatchPrediction && typeof preMatchPrediction === "object") {
    const pmPred = preMatchPrediction.predictions || {};
    const pmComp = preMatchPrediction.comparison || {};
    const pmTeams = preMatchPrediction.teams || {};

    preMatchEnhanced = {
      // Core predictions
      favourite: pmPred.winner?.name || null,
      favourite_comment: pmPred.winner?.comment || null,  // "Win or draw"
      win_or_draw: pmPred.win_or_draw ?? null,
      under_over: pmPred.under_over || null,  // "+2.5" or "-2.5"
      expected_goals: pmPred.goals || null,
      win_percent: pmPred.percent || null,
      advice: pmPred.advice || null,

      // Comparison metrics
      comparison: {
        form: pmComp.form || null,
        attack: pmComp.att || null,
        defense: pmComp.def || null,
        h2h: pmComp.h2h || null,
        total: pmComp.total || null
      },

      // HOME team detailed stats
      home_stats: pmTeams.home ? {
        last_5: pmTeams.home.last_5,           // { form, attack, defense, avg_scored, avg_conceded }
        season_form: pmTeams.home.season_form, // "WDLDDLDWDDLLLWWWWLWWL"
        record: pmTeams.home.record,           // { played, wins, draws, loses, total }
        goals_by_minute: pmTeams.home.goals_by_minute,  // { scored: {0-15: %, ...}, conceded: {...} }
        avg_goals: pmTeams.home.avg_goals,     // { scored, conceded }
        clean_sheets: pmTeams.home.clean_sheets,
        failed_to_score: pmTeams.home.failed_to_score,
        biggest_streak: pmTeams.home.biggest_streak,
        under_over: pmTeams.home.under_over    // O/U statistics
      } : null,

      // AWAY team detailed stats
      away_stats: pmTeams.away ? {
        last_5: pmTeams.away.last_5,
        season_form: pmTeams.away.season_form,
        record: pmTeams.away.record,
        goals_by_minute: pmTeams.away.goals_by_minute,
        avg_goals: pmTeams.away.avg_goals,
        clean_sheets: pmTeams.away.clean_sheets,
        failed_to_score: pmTeams.away.failed_to_score,
        biggest_streak: pmTeams.away.biggest_streak,
        under_over: pmTeams.away.under_over
      } : null
    };
  }

  // Determine mode (pre-match vs in-play) WITHOUT assuming
  const runMode = (minute === null || minute === undefined) ? "PRE_MATCH" : "IN_PLAY";

  return {
    matchId,
    homeName,
    awayName,
    league,
    minute,
    score,
    status,
    statsAvailable,
    statsCompact,
    events,
    oddsAvailable,
    oddsCanonical,
    preMatchEnhanced,
    preMatchPredictionSummary,
    customConditionsExisting,
    runMode
  };
}

// --------------------
// Build context cho tất cả matches trong batch
// --------------------
const matchContexts = matches.map(m => buildMatchContext(m));

// Xác định RUN_MODE chung (dựa trên match đầu tiên hoặc majority)
const commonRunMode = matchContexts[0]?.runMode || "PRE_MATCH";

// --------------------
// Build MATCHES CONTEXT section với ENHANCED data
// --------------------
const matchesContextStr = matchContexts.map((ctx, idx) => `
--- MATCH ${idx + 1} ---
match_id: ${ctx.matchId}
Match: ${ctx.homeName} vs ${ctx.awayName}
