function extractJsonArray(text) {
  if (!text) return null;
  const codeBlockMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (codeBlockMatch) {
    const inner = codeBlockMatch[1].trim();
    const arrMatch = inner.match(/\[[\s\S]*\]/);
    if (arrMatch) return arrMatch[0];
  }
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  return jsonMatch ? jsonMatch[0] : null;
}

function getAiText(src) {
  try {
    if (src?.candidates?.[0]?.content?.parts?.[0]?.text) return src.candidates[0].content.parts[0].text; // Gemini
    if (src?.content?.[0]?.text) return src.content[0].text; // Claude
    if (typeof src?.text === 'string') return src.text;
    if (typeof src?.result === 'string') return src.result;
  } catch (e) {}
  return '';
}

const aiItems = $input.all();
const buildItems = $items('Build AI Prompt'); // mỗi item là 1 batch { ai_prompt, matches, batch_index }

const outputs = [];

for (let i = 0; i < aiItems.length; i++) {
  const src = aiItems[i].json || {};
  const batchData = buildItems[i]?.json || {};
  const originalMatches = Array.isArray(batchData.matches) ? batchData.matches : [];
  const batchIndex = batchData.batch_index ?? (i + 1);

  const aiRawText = getAiText(src);

  let results = [];
  let parseError = null;

  const jsonStr = extractJsonArray(aiRawText);
  if (jsonStr) {
    try {
      results = JSON.parse(jsonStr);
      if (!Array.isArray(results)) results = [];
    } catch (err) {
      parseError = String(err);
      results = [];
    }
  } else {
    parseError = 'NO_JSON_ARRAY_FOUND';
  }

  const resultMap = new Map();
  for (const r of results) {
    if (r?.match_id != null) resultMap.set(String(r.match_id), r);
  }

  console.log(`[Parse] Batch ${batchIndex} had ${originalMatches.length} matches, AI returned ${results.length} results`);

  for (const match of originalMatches) {
    const matchId = String(match?.match_id ?? '');
    const result = resultMap.get(matchId) || {};

    outputs.push({
      json: {
        batch_index: batchIndex,

        match_id: match?.match_id,
        home_team: match?.home_team,
        away_team: match?.away_team,
        league: match?.league,
        mode: match?.mode,
        priority: match?.priority,
        custom_conditions: match?.custom_conditions,
        row_number: match?.row_number,

        should_write: !!result?.condition,
        recommended_custom_condition: result?.condition || '',
        reason: result?.reason || '',
        // ============================================================
        // NEW: Extract Vietnamese translation
        // ============================================================
        reason_vi: result?.reason_vi || '',

        has_prediction: match?.has_prediction,
        pre_match_prediction_summary: match?.pre_match_prediction_summary,
        parse_error: parseError,
      }
    });
  }
}

return outputs;

