// Log skipped items
const items = $input.all();

const skipped = items.map(i => ({
  match_id: i.json.match_id,
  match: `${i.json.home_team} vs ${i.json.away_team}`,
  reason: i.json.reason || 'No condition generated',
  parse_error: i.json.parse_error,
}));

console.log(`[Skipped] ${skipped.length} items without conditions`);
return [{ json: { skipped_count: skipped.length, skipped } }];
